package org.apache.commons.math3.optim;

public class SimplePointChecker < PAIR extends Pair < double [ ] , ? extends Object > > extends AbstractConvergenceChecker < PAIR > { private static final int ITERATION_CHECK_DISABLED = - 1 ; private final int maxIterationCount ; public SimplePointChecker ( final double relativeThreshold , final double absoluteThreshold ) { super ( relativeThreshold , absoluteThreshold ) ; maxIterationCount = ITERATION_CHECK_DISABLED ; } public SimplePointChecker ( final double relativeThreshold , final double absoluteThreshold , final int maxIter ) { super ( relativeThreshold , absoluteThreshold ) ; if ( maxIter <= 0 ) { throw new NotStrictlyPositiveException ( maxIter ) ; } maxIterationCount = maxIter ; } @ Override public boolean converged ( final int iteration , final PAIR previous , final PAIR current ) { if ( maxIterationCount != ITERATION_CHECK_DISABLED && iteration >= maxIterationCount ) { return true ; } final double [ ] p = previous . getKey ( ) ; final double [ ] c = current . getKey ( ) ; for ( int i = 0 ; i < p . length ; ++ i ) { final double pi = p [ i ] ; final double ci = c [ i ] ; final double difference = FastMath . abs ( pi - ci ) ; final double size = FastMath . max ( FastMath . abs ( pi ) , FastMath . abs ( ci ) ) ; if ( difference > size * getRelativeThreshold ( ) && difference > getAbsoluteThreshold ( ) ) { return false ; } } return true ; } }